const TOKEN = 'sbp_f314cf27b5b2a01eea48048a7b1c015cc9cf4b42'
const API = 'https://api.supabase.com/v1/projects/amhfxaqolholacanqyas/database/query'
function esc(s) { return s.replace(/'/g, "''") }
async function insert(batch) {
  const values = batch.map(q => {
    const opts = JSON.stringify(q.options).replace(/'/g, "''")
    return `('en','${q.cat}','${esc(q.s)}','${esc(q.t)}','${opts}'::jsonb,${q.d},'claude',true)`
  }).join(',')
  const sql = `INSERT INTO questions (locale,category,scenario_text,mindset_tip,options,difficulty,generated_by,is_active) VALUES ${values};`
  const r = await fetch(API, {method:'POST',headers:{'Authorization':`Bearer ${TOKEN}`,'Content-Type':'application/json'},body:JSON.stringify({query:sql})})
  const d = await r.json()
  if(d.message) { console.error('ERR:',d.message.substring(0,120)); return false }
  console.log('OK:', batch.length, 'inserted')
  return true
}

const ALL = [

// ===== ai-education (20) =====
{cat:'ai-education',d:1,s:'A university professor wants to use AI to give students personalized feedback on essays but worries it will replace the teacher-student relationship.',t:'AI feedback tools augment teaching by handling volume, giving teachers more time for the deeper conversations that matter most.',options:[
  {text:'Let AI grade and provide final feedback on all essays without teacher review',score:-100,feedbackText:'AI feedback without teacher oversight misses the nuanced judgment that distinguishes good writing from technically correct writing.'},
  {text:'Use AI for first-pass feedback on mechanics and structure while the professor focuses on conceptual depth and personal growth in office hours',score:100,feedbackText:'Correct! AI handles volume; humans handle depth. This frees the professor for the interactions where human insight is irreplaceable.'},
  {text:'Give AI feedback only to the bottom half of the class since top students need less help',score:0,feedbackText:'Performance-based AI access creates a two-tier system. AI feedback benefits all students, including high performers who can use it to push further.'}
]},
{cat:'ai-education',d:2,s:'A school district wants to use AI tutors to personalize math instruction for 50,000 students. Budget is limited.',t:'Personalized AI learning tools are most effective when teachers understand how to use the data they generate to intervene at the right moments.',options:[
  {text:'Deploy AI tutors across all schools and reduce teaching staff proportionally',score:-100,feedbackText:'AI tutors supplement instruction but cannot replace the relational, motivational, and adaptive dimensions of effective teaching.'},
  {text:'Pilot AI tutors in three schools, train teachers to interpret the learning analytics, measure outcomes at 6 months, then scale with teacher-centered implementation',score:100,feedbackText:'Excellent! Pilot-first with teacher training is the right approach. AI learning tools fail when teachers cannot act on the data they produce.'},
  {text:'Give students AI tutor access as a homework supplement without changing classroom instruction',score:0,feedbackText:'Homework supplement use misses the classroom integration where AI personalization has the highest impact. Teacher involvement dramatically improves outcomes.'}
]},
{cat:'ai-education',d:1,s:'A student uses AI to summarize textbook chapters instead of reading them, then struggles on the exam covering deeper concepts.',t:'AI summarization is a study tool, not a reading replacement. Deep understanding requires engagement with source material that summaries cannot provide.',options:[
  {text:'Ban AI tools in educational settings since students use them to avoid learning',score:-100,feedbackText:'Banning tools does not address the underlying study behavior. Teaching students when and how to use AI effectively builds durable skills.'},
  {text:'Teach students to use AI summaries as a preview or review tool, then read the source material for the depth that exams require',score:100,feedbackText:'Correct! AI summaries are excellent for orientation and review but cannot replace deep reading for conceptual mastery. Teaching this distinction is the educator\'s role.'},
  {text:'Make exams easier so that summary-level knowledge is sufficient to pass',score:0,feedbackText:'Lowering standards to match the tool inverts the relationship between education and technology. Students need to learn to use tools within the demands of rigorous learning.'}
]},
{cat:'ai-education',d:2,s:'A corporate learning team wants to use AI to create personalized onboarding paths for new employees across twelve departments.',t:'Personalized onboarding with AI reduces time-to-productivity by tailoring content to the individual\'s role, experience level, and learning pace.',options:[
  {text:'Create one universal AI onboarding path and let employees skip modules they already know',score:0,feedbackText:'Self-directed skipping requires employees to know what they do not know, which new hires reliably underestimate. AI-driven sequencing based on assessment is more reliable.'},
  {text:'Use pre-hire assessments to feed AI with each employee\'s background, then generate a personalized path that skips mastered content and adds depth where gaps exist',score:100,feedbackText:'Excellent! Assessment-driven personalization ensures each employee gets exactly what they need without wasting time on content they have already mastered.'},
  {text:'Hire more HR staff to run in-person onboarding for all twelve departments',score:-100,feedbackText:'In-person onboarding is valuable for culture and connection, but AI-personalized content paths scale to twelve departments without proportional staffing increases.'}
]},
{cat:'ai-education',d:3,s:'Students at a high school have started using AI to write their essays. The school wants to detect AI writing but detection tools have high false positive rates.',t:'Detection-based approaches to AI in education are a losing battle. Pedagogy that develops genuine skills is more sustainable than detection arms races.',options:[
  {text:'Deploy the detection tool despite false positives and investigate any flagged student',score:-100,feedbackText:'High false positive rates mean accusing students who did not use AI. The reputational and legal risk of misidentification is serious and erodes trust.'},
  {text:'Shift assignments to forms that AI cannot easily complete: in-class writing, oral defense, portfolio with drafts, or projects requiring personal experience',score:100,feedbackText:'Correct! Assignment redesign addresses the root cause rather than chasing a detection technology that will always lag behind the tools students use.'},
  {text:'Allow AI use openly and focus only on teaching students to critically evaluate AI output',score:0,feedbackText:'Open use plus critical evaluation is part of a sustainable approach but without skill-building assignments, students do not develop independent writing capabilities.'}
]},
{cat:'ai-education',d:1,s:'A language teacher wants to use AI conversation practice tools so students can speak the target language more outside of class.',t:'AI conversation tools increase speaking practice volume between classes, which is critical for fluency since one class per day is not enough.',options:[
  {text:'Replace in-class speaking practice with AI tools to maximize total speaking time',score:0,feedbackText:'AI tools cannot provide the cultural context, emotional connection, or natural conversation variation that peer interaction offers. Both have distinct value.'},
  {text:'Assign AI conversation tools for 15-minute daily practice sessions between classes while reserving class time for peer interaction and teacher feedback',score:100,feedbackText:'Excellent! Daily AI practice plus class interaction creates the volume and variety fluency requires. AI cannot replace the teacher but it massively increases practice time.'},
  {text:'Skip AI conversation tools since they lack the authenticity of real human interaction',score:-100,feedbackText:'Authenticity matters, but fluency requires volume. AI practice tools let students make mistakes in a low-stakes environment that accelerates confidence.'}
]},
{cat:'ai-education',d:2,s:'A university wants to use AI to predict which students are at risk of dropping out so advisors can intervene early.',t:'AI early warning systems are only valuable if the intervention capacity exists to respond to every flag the system raises.',options:[
  {text:'Deploy the AI prediction system and have advisors prioritize flagged students',score:0,feedbackText:'Prioritizing flagged students is good but if advisor capacity cannot absorb the flagged volume, many at-risk students still fall through the cracks.'},
  {text:'Assess advisor capacity first, calibrate the flag rate to match available response capacity, and build the intervention workflow before deploying the prediction system',score:100,feedbackText:'Correct! Prediction without response capacity is theater. The system works only when every flag results in an actual advisement touchpoint.'},
  {text:'Share the risk scores with students directly so they can self-refer to advising',score:-100,feedbackText:'Sharing algorithmic risk scores with students can feel stigmatizing and may undermine confidence. Institutional response to AI flags should not be outsourced to the flagged individual.'}
]},
{cat:'ai-education',d:1,s:'A training manager wants to use AI to generate quiz questions from a new compliance manual so employees can test their understanding.',t:'AI quiz generation from source documents dramatically reduces content development time while maintaining accuracy, especially for factual compliance content.',options:[
  {text:'Have subject matter experts write all quiz questions manually to ensure quality',score:0,feedbackText:'Manual question writing by SMEs produces high quality but is slow and expensive. AI generation with SME review captures quality at a fraction of the time.'},
  {text:'Generate quiz questions with AI from the compliance manual, have a legal or compliance expert review for accuracy, then deploy',score:100,feedbackText:'Excellent! AI handles volume; expert review ensures compliance accuracy. This process produces a validated quiz bank at a fraction of the manual development cost.'},
  {text:'Require employees to read the manual without a quiz since self-study accountability is a professional skill',score:-100,feedbackText:'Self-study without assessment consistently produces lower retention than tested learning. Compliance training especially benefits from verified comprehension.'}
]},
{cat:'ai-education',d:3,s:'An AI tutoring system has been shown to improve test scores but also reduces collaboration between students during study sessions.',t:'Learning outcome metrics like test scores can improve while social-emotional learning dimensions decline. Both matter for long-term development.',options:[
  {text:'Expand AI tutoring since test scores are the primary measure of educational success',score:0,feedbackText:'Test scores are important but incomplete. Educational research consistently shows that collaboration skills affect long-term career outcomes as much as academic performance.'},
  {text:'Use AI tutoring for individual skill practice while redesigning collaborative activities to leverage the freed-up time in new ways',score:100,feedbackText:'Correct! Augmenting individual practice with AI while redesigning collaboration preserves the interpersonal development that scores cannot capture.'},
  {text:'Remove AI tutoring to restore collaboration patterns to previous levels',score:-100,feedbackText:'Removing a tool that improves test scores because of a side effect ignores the option of redesigning the environment to capture both benefits.'}
]},
{cat:'ai-education',d:2,s:'An online course platform wants to use AI to recommend the next course to each learner based on their completion history.',t:'AI recommendation in learning platforms works best when it balances completion data with learning goal alignment, not just engagement prediction.',options:[
  {text:'Recommend the most popular next course among users with similar histories',score:0,feedbackText:'Popularity-based recommendations optimize for the average learner rather than the individual. They often lead to entertaining courses rather than goal-aligned ones.'},
  {text:'Recommend courses that align with the learner\'s stated goals, fill demonstrated skill gaps from assessment data, and sequence progressively toward mastery',score:100,feedbackText:'Excellent! Goal and gap-aligned recommendations serve learners rather than platform metrics. The distinction between what learners want and what keeps them engaged matters here.'},
  {text:'Let learners browse all courses without algorithmic recommendations to maintain autonomy',score:-100,feedbackText:'Unlimited choice creates decision fatigue and often results in learners not progressing. Smart recommendations reduce friction toward their own stated goals.'}
]},
{cat:'ai-education',d:1,s:'A teacher wants to use AI to differentiate worksheets so each student receives material at their own reading level.',t:'AI differentiation tools that adjust text complexity to individual levels reduce both boredom for advanced students and frustration for struggling ones.',options:[
  {text:'Create one worksheet at grade level and encourage strong students to help weaker ones',score:0,feedbackText:'Peer learning has value but cannot substitute for material that meets each student where they are. Mixed-ability helping dynamics also create social dynamics not all students benefit from.'},
  {text:'Use AI to generate the same content at three reading levels and assign each student the appropriate version based on their assessed reading level',score:100,feedbackText:'Correct! Leveled materials produced by AI solve the differentiation problem at scale. Teachers cannot produce three versions manually for every assignment — AI makes it feasible.'},
  {text:'Abandon differentiation since tracking by reading level is stigmatizing',score:-100,feedbackText:'Stigma from labeling is real but solved by how differentiation is communicated, not by abandoning it. Presenting all materials as "different challenge levels" removes most stigma.'}
]},
{cat:'ai-education',d:2,s:'A corporate training team built an AI simulation for leadership scenarios. Participation is low because employees say it feels unrealistic.',t:'Simulation realism is critical for transfer of learning. Low participation signals that the gap between simulation and real-world stakes is too wide.',options:[
  {text:'Make participation mandatory to improve completion rates',score:-100,feedbackText:'Mandatory participation in a tool employees find unrealistic produces low engagement and no learning transfer. Fixing the tool is the only sustainable solution.'},
  {text:'Collect specific feedback on what feels unrealistic, update scenarios with actual leadership dilemmas from the organization\'s history, and pilot the revised version with a focus group',score:100,feedbackText:'Excellent! Real organizational scenarios bridge the realism gap. Employees engage with simulations that feel like actual decisions they might face, not generic business school cases.'},
  {text:'Replace the simulation with in-person role-plays since technology cannot replicate human interaction',score:0,feedbackText:'In-person role-plays have value but are expensive and hard to scale. Improving simulation realism is more scalable than replacing it with an inherently limited-capacity alternative.'}
]},
{cat:'ai-education',d:3,s:'An AI tutoring company claims their product increases student outcomes by 35%. You are a school administrator evaluating the purchase.',t:'AI EdTech claims require scrutiny: what was measured, on which population, compared to what baseline, and whether the study was independent.',options:[
  {text:'Purchase the product based on the 35% improvement claim since it is a significant outcome',score:-100,feedbackText:'Marketing claims without scrutiny of methodology are not evidence. A 35% improvement measured against a flawed baseline with a selected sample proves almost nothing.'},
  {text:'Ask for the study details: sample characteristics, comparison group, what outcome was measured, who funded the research, and whether peer review occurred',score:100,feedbackText:'Correct! These four questions reveal whether the evidence is genuine. Vendor-funded studies without peer review and with cherry-picked samples routinely produce inflated claims.'},
  {text:'Pilot the product with a small group of students before deciding on purchase',score:0,feedbackText:'A pilot is a good next step but should follow rather than replace scrutiny of the existing evidence. A bad product can show good results in a short pilot due to novelty effects.'}
]},
{cat:'ai-education',d:1,s:'Parents at a school are concerned that AI grading tools will evaluate their children\'s work based on word patterns rather than genuine understanding.',t:'AI grading tools should be transparent about what they measure and used as one input alongside teacher judgment, not as a replacement for it.',options:[
  {text:'Dismiss the parental concern since AI grading tools are validated and accurate',score:-100,feedbackText:'Dismissing parental concern erodes trust. The concern about pattern-matching vs. understanding is technically valid and deserves an honest answer.'},
  {text:'Explain openly what the AI grades and does not grade, confirm teacher review remains part of all final marks, and invite parents to see examples',score:100,feedbackText:'Excellent! Transparency and teacher-in-the-loop assurance directly addresses the concern. Inviting parents to see examples converts abstract fear into concrete understanding.'},
  {text:'Stop using AI grading to avoid parental conflict',score:0,feedbackText:'Avoiding conflict by abandoning useful tools is not a governance model. Engaging parents with honest explanation is more sustainable than tool withdrawal.'}
]},
{cat:'ai-education',d:2,s:'A medical school wants to use AI to give clinical reasoning feedback to students on patient case simulations.',t:'AI clinical feedback is most valuable when it explains the reasoning behind each evaluation step, not just whether the student\'s answer was right or wrong.',options:[
  {text:'Use AI to mark cases right or wrong and provide the correct answer',score:0,feedbackText:'Binary right/wrong feedback in clinical training produces memorization rather than reasoning development. Medical AI feedback must model the thought process, not just the answer.'},
  {text:'Configure AI to give step-by-step reasoning feedback that explains why a clinical decision was optimal or suboptimal in the context of the case',score:100,feedbackText:'Correct! Reasoning-level feedback develops clinical thinking. Students who understand why a decision was wrong can generalize that understanding to novel cases.'},
  {text:'Assign AI cases as homework only since clinical reasoning requires faculty supervision',score:-100,feedbackText:'AI simulations are scalable practice tools that let students work through many more cases than faculty-supervised time allows. The two are complementary, not competing.'}
]},
{cat:'ai-education',d:3,s:'Your company\'s employee training completion rates are high but post-training performance improvement is minimal.',t:'Completion rates measure whether people started and finished training, not whether they learned anything or can apply it. Better metrics reveal better insights.',options:[
  {text:'Add more training modules since employees who complete more training should improve more',score:-100,feedbackText:'More training that does not work is more waste. The completion-performance gap signals that the training content or design is the problem, not the volume.'},
  {text:'Measure pre- and post-training skill assessments, track on-the-job behavior change with manager ratings, and compare performance metrics for trained vs. untrained cohorts',score:100,feedbackText:'Excellent! Multi-layer outcome measurement reveals where the training effect breaks down. If skills improve but behavior does not change, the application support is missing.'},
  {text:'Survey employees on what they found most valuable in the training and iterate based on feedback',score:0,feedbackText:'Learner satisfaction surveys are useful for content design but do not correlate well with performance outcomes. Direct performance measurement is needed.'}
]},
{cat:'ai-education',d:1,s:'A teacher notices that AI writing assistance has improved the final quality of student essays but students seem less invested in the writing process.',t:'The process of writing builds thinking skills that the polished output alone does not reveal. AI assistance must be structured to develop the student, not just the document.',options:[
  {text:'Remove AI assistance from writing assignments to restore student ownership',score:0,feedbackText:'Removing tools does not restore ownership if the root issue is how tasks are designed. Redesigned tasks with AI in a structured role preserve both quality and development.'},
  {text:'Redesign assignments to require visible drafting stages, reflection on AI suggestions, and defense of final choices so students remain intellectually engaged throughout',score:100,feedbackText:'Correct! Structured integration with reflection requirements makes AI a thinking partner rather than a thinking replacement. The cognitive work must happen; AI should facilitate, not bypass it.'},
  {text:'Keep using AI assistance since the improved final quality is the goal of writing assignments',score:-100,feedbackText:'If the goal is thinking development, polished AI-assisted output is a Pyrrhic victory. Assessment should evaluate the student\'s thinking, not the quality of AI collaboration.'}
]},
{cat:'ai-education',d:2,s:'You are designing a professional development program for teachers on AI literacy. Teachers are skeptical and feel their expertise is being questioned.',t:'AI professional development lands best when it starts from teachers\' expertise and shows how AI extends it, rather than positioning AI as a replacement.',options:[
  {text:'Lead with what AI can do that teachers cannot, to demonstrate why the training matters',score:-100,feedbackText:'Starting with AI capabilities that exceed teacher abilities activates defensiveness and resistance. The message received is that teachers are inadequate, not that they are being empowered.'},
  {text:'Start from teachers\' existing instructional challenges and show how AI tools address those specific problems, positioning teachers as experts who direct the AI',score:100,feedbackText:'Excellent! Problem-first framing centered on teachers\' authority is the most effective professional development design. Teachers who see AI as a tool they control adopt it far more readily.'},
  {text:'Require all teachers to complete AI training regardless of their interest level',score:0,feedbackText:'Mandatory training without addressing skepticism produces compliance rather than adoption. Engagement with the concerns is a prerequisite for genuine uptake.'}
]},
{cat:'ai-education',d:1,s:'A university library wants to use AI to help students formulate better research questions for their papers.',t:'Strong research questions drive better papers. AI that helps students sharpen and narrow their questions adds more educational value than AI that answers them.',options:[
  {text:'Build an AI tool that helps students find sources for their existing research question',score:0,feedbackText:'Source finding is valuable but secondary to question quality. A poorly formed question produces a poorly formed paper regardless of source quality.'},
  {text:'Build an AI tool that challenges students\' initial questions with follow-up prompts about scope, arguability, and relevance until the question is genuinely research-worthy',score:100,feedbackText:'Correct! Question refinement AI changes the upstream quality of all subsequent work. It is more educationally valuable than downstream assistance with sources or writing.'},
  {text:'Let students consult with librarians for question formulation since AI lacks academic judgment',score:-100,feedbackText:'Librarian consultations are valuable but cannot serve all students at scale. AI question refinement tools extend research guidance capacity without reducing librarian availability for complex needs.'}
]},
{cat:'ai-education',d:2,s:'A company wants to use AI to generate a leadership curriculum for new managers. The HR team has no curriculum design expertise.',t:'AI can accelerate curriculum development but requires domain expertise input and learning science principles to produce training that actually changes behavior.',options:[
  {text:'Have AI generate the complete curriculum independently and launch it',score:-100,feedbackText:'AI-generated curriculum without expert input produces generic content that lacks organizational context and often misses the specific leadership challenges new managers face.'},
  {text:'Have HR interview experienced managers about real challenges, feed those insights to AI for curriculum structure, then have a learning designer review for instructional quality',score:100,feedbackText:'Excellent! Expert input plus AI structure plus learning design review combines the strengths of each. The result is contextually relevant and pedagogically sound.'},
  {text:'Buy an existing off-the-shelf leadership curriculum since building takes too long',score:0,feedbackText:'Generic curriculum misses the organization-specific context that makes leadership training transferable. AI-assisted custom development is now fast enough to compete with off-the-shelf.'}
]},

// ===== ai-everyday (20) =====
{cat:'ai-everyday',d:1,s:'You want to use AI to help plan meals for the week but you are not sure if you should share your health conditions with a consumer AI tool.',t:'Consumer AI tools are not medical services. Health-sensitive information entered into them may be stored and used in ways users do not expect.',options:[
  {text:'Share your full medical history to get the most personalized meal recommendations',score:-100,feedbackText:'Consumer AI apps are not HIPAA-compliant medical services. Sharing detailed health information with them creates privacy risks that outweigh the personalization benefit.'},
  {text:'Share general dietary preferences like vegetarian or low-sodium without specific diagnoses, and consult a dietitian for medically significant conditions',score:100,feedbackText:'Correct! General preferences give AI enough to personalize without exposing sensitive health data. Medical nutrition advice belongs with qualified professionals, not consumer apps.'},
  {text:'Avoid using AI for meal planning entirely since health information is involved',score:0,feedbackText:'Avoiding AI altogether is overly cautious for general meal planning. The key is managing what you share, not avoiding the tool.'}
]},
{cat:'ai-everyday',d:1,s:'You want to use an AI calendar assistant to manage your schedule but worry about sharing your location data with it.',t:'AI tools that require location data for useful features should have minimal data retention settings reviewed before enabling location access.',options:[
  {text:'Enable full location access since the assistant cannot help without it',score:0,feedbackText:'Full location access may be more than the feature requires. Checking whether the feature works with approximate location or location by exception is worth a few minutes.'},
  {text:'Review the app\'s location data retention settings, enable only the minimum access level needed, and turn off background location tracking',score:100,feedbackText:'Excellent! Minimum access is the right privacy posture for AI tools. Most scheduling features work adequately with approximate location or on-demand access.'},
  {text:'Refuse all location access and manually enter locations since AI should not know where you are',score:-100,feedbackText:'Full refusal sacrifices useful features unnecessarily. Reviewing settings is more proportionate than refusing the feature entirely.'}
]},
{cat:'ai-everyday',d:2,s:'Your elderly parent wants to use an AI voice assistant to help them remember medications and appointments. You are setting it up for them.',t:'AI assistants for elderly users need simplified interfaces, clear error messages, and easy reset paths since complex recovery steps are inaccessible.',options:[
  {text:'Configure the assistant with all available features enabled to maximize its usefulness',score:-100,feedbackText:'Maximum features create maximum complexity. An elderly user who encounters a confusing state has no clear path back. Simplicity prevents abandonment.'},
  {text:'Enable only medication reminders and appointment alerts, test recovery from common errors, and leave a written quick-start guide nearby',score:100,feedbackText:'Correct! Scoped setup plus tested error recovery plus physical reference guide creates a system an elderly user can rely on without needing technical support.'},
  {text:'Set it up exactly as you would for yourself since the features are the same',score:0,feedbackText:'Your own setup optimizes for your capabilities. Elderly users have different interaction patterns and failure recovery needs that require deliberate simplified configuration.'}
]},
{cat:'ai-everyday',d:1,s:'You want AI to help you find the best price on a large appliance purchase. Three different AI tools give you conflicting recommendations.',t:'AI shopping assistants have different training data, affiliations, and update frequencies. Cross-checking multiple sources plus direct retailer verification produces the most reliable price.',options:[
  {text:'Trust the AI tool with the most professional interface since design reflects quality',score:-100,feedbackText:'Interface quality does not correlate with data accuracy. Polished AI tools can have outdated or sponsored price data regardless of how they look.'},
  {text:'Note where two or more tools agree, then verify those prices directly on the retailer\'s website before purchasing',score:100,feedbackText:'Excellent! Consensus across tools reduces noise, and direct retailer verification eliminates the risk of cached or inaccurate AI data. This two-step process is reliable.'},
  {text:'Ask a fourth AI tool to break the tie among the first three',score:0,feedbackText:'Adding more AI opinions without primary source verification just adds more noise. Retailer website prices are ground truth — check those directly.'}
]},
{cat:'ai-everyday',d:2,s:'An AI writing tool auto-corrected your text message in a way that completely changed your meaning before you sent it.',t:'AI auto-correction in communication tools requires active review since it optimizes for linguistic convention, not intended meaning.',options:[
  {text:'Disable auto-correction entirely since it creates more problems than it solves',score:0,feedbackText:'Complete disabling removes the benefit of catching genuine errors. Reviewing before sending is more useful than eliminating the feature.'},
  {text:'Always review AI-corrected messages before sending and use a manual override when the correction changes your intended meaning',score:100,feedbackText:'Correct! Review before send is the sustainable habit. Auto-correction is most dangerous when it changes meaning invisibly — a quick read catches this every time.'},
  {text:'Trust auto-correction since AI language models understand context well enough to preserve meaning',score:-100,feedbackText:'AI auto-correction optimizes for linguistic convention and grammar, not your specific intent. Meaning changes are especially common with idiomatic, domain-specific, or ironic text.'}
]},
{cat:'ai-everyday',d:1,s:'You want to use AI to help you write a complaint letter to your landlord about repair delays.',t:'AI helps you write firmly and professionally in difficult situations where emotional language might undermine your position.',options:[
  {text:'Let AI write the complete letter with the most aggressive possible tone to show you are serious',score:-100,feedbackText:'Aggressive letters escalate conflict and can damage your legal position. Firm, factual, professionally toned letters are more effective and legally safer.'},
  {text:'Describe your situation to AI, ask for a firm but professional tone, review the draft, and add specific dates and documentation references before sending',score:100,feedbackText:'Excellent! AI structures the language; you provide the facts. A professional tone gets results where emotional language often derails resolution.'},
  {text:'Write the letter yourself without AI since a complaint letter should reflect your personal frustration',score:0,feedbackText:'Personal frustration expressed as emotion rarely serves your objective of getting repairs done. AI-assisted professional framing is more effective at achieving the goal.'}
]},
{cat:'ai-everyday',d:2,s:'Your teenager wants to use AI for homework help and you want to understand the risks before deciding.',t:'AI homework assistance ranges from scaffolded learning support to complete answer generation — the difference is in how it is used, not the tool itself.',options:[
  {text:'Ban AI homework use entirely since it enables academic dishonesty',score:0,feedbackText:'Blanket bans are difficult to enforce and miss the educational opportunity. Teaching the right way to use AI for learning is more valuable than prohibition.'},
  {text:'Allow AI as a tutor that explains concepts and guides thinking, but not as an answer generator — check by asking your teenager to explain their homework to you',score:100,feedbackText:'Correct! The "explain it to me" check reliably reveals whether understanding occurred or just output was captured. This turns AI use into a verifiable learning process.'},
  {text:'Allow unrestricted AI use since the skill of working effectively with AI is itself a valuable competency',score:-100,feedbackText:'AI collaboration is a valuable skill but must be built on genuine understanding. Unrestricted answer generation produces neither skill — only the appearance of completion.'}
]},
{cat:'ai-everyday',d:1,s:'You want AI to help you prepare for a difficult conversation with a family member about a sensitive topic.',t:'AI can help you anticipate reactions, organize your thoughts, and rehearse responses so you enter difficult conversations more grounded.',options:[
  {text:'Ask AI to script the entire conversation so you know exactly what to say',score:-100,feedbackText:'Scripted conversations feel unnatural and collapse when the other person deviates from the expected path. Preparation for flexibility is more useful than memorized scripts.'},
  {text:'Use AI to organize your main points, anticipate likely reactions, and practice responses to the most challenging things you might hear',score:100,feedbackText:'Excellent! Preparation for reactions is more valuable than scripting your own lines. Understanding where the conversation might go hard keeps you grounded when it does.'},
  {text:'Have the conversation without preparation since authentic responses are better than planned ones',score:0,feedbackText:'Authentic does not mean unprepared. Knowing your goals and having considered the likely responses makes you more present and effective, not less authentic.'}
]},
{cat:'ai-everyday',d:3,s:'You notice that AI news aggregators have started giving you only stories that confirm your existing views. You feel well-informed but your friends hold very different views on the same events.',t:'AI recommendation systems optimize for engagement, which often means reinforcing existing beliefs. Actively seeking opposing perspectives is a necessary counter-habit.',options:[
  {text:'Trust your AI news feed since it filters for relevance and you can evaluate articles critically',score:-100,feedbackText:'Critical evaluation of articles within a filtered feed does not address the selection bias. You can think critically about articles you see without realizing what you are not seeing.'},
  {text:'Regularly read sources with different editorial perspectives and use AI to summarize opposing viewpoints on major issues so you see the full range of arguments',score:100,feedbackText:'Correct! Active diversity-seeking counters filter bubble dynamics. Using AI to summarize opposing views is an efficient way to expose yourself to the range of arguments.'},
  {text:'Reduce news consumption since filter bubbles are unavoidable with AI curation',score:0,feedbackText:'Reduced consumption avoids filter bubbles only by avoiding all information. Actively seeking diverse sources is a better response than withdrawal.'}
]},
{cat:'ai-everyday',d:1,s:'You want to use an AI fitness app to create a personalized workout plan. The app asks for detailed health metrics.',t:'AI fitness apps can personalize effectively with basic metrics. Medical conditions require professional fitness guidance, not consumer AI customization.',options:[
  {text:'Enter every health metric the app requests including medications and medical diagnoses to maximize personalization',score:0,feedbackText:'More input enables better personalization but consumer fitness apps are not the right platform for sensitive medical data. Share general fitness data; save diagnoses for professionals.'},
  {text:'Provide age, fitness goals, current activity level, and physical limitations but consult a personal trainer or physical therapist for exercise plans involving medical conditions',score:100,feedbackText:'Correct! General fitness data gives AI enough to personalize effectively. Exercise involving medical conditions needs professional oversight that AI fitness apps are not equipped to provide.'},
  {text:'Use the app without entering any personal data since privacy is more important than personalization',score:-100,feedbackText:'Refusing all input prevents meaningful personalization. The goal is proportionate data sharing — enough for useful output, not more than the context warrants.'}
]},
{cat:'ai-everyday',d:2,s:'An AI travel planner suggests a detailed itinerary for your trip but you notice some attractions are listed as open that you know have permanently closed.',t:'AI travel information may be outdated, especially for local businesses. Real-time verification with official sources is always necessary before booking.',options:[
  {text:'Follow the AI itinerary exactly since it is based on comprehensive travel data',score:-100,feedbackText:'AI travel data has training cutoffs and cannot know about recent closures. Following an unverified itinerary risks wasted travel days and booking errors.'},
  {text:'Use the AI itinerary as a planning starting point, then verify each attraction\'s current status through their official website or a recent review',score:100,feedbackText:'Excellent! AI provides structure; verification provides accuracy. This combination produces an itinerary that is both well-organized and actually possible to execute.'},
  {text:'Ask the AI tool if its information is current before deciding whether to verify',score:0,feedbackText:'Asking AI about its own currency is unreliable — it may not know what it does not know. Direct verification with official sources is always the safer approach.'}
]},
{cat:'ai-everyday',d:1,s:'You want to use AI to help write a eulogy for a family member. The process feels inappropriate to delegate to an AI.',t:'Using AI as a writing partner for emotional documents is not delegating your grief — it is getting help translating deeply personal feelings into words.',options:[
  {text:'Write everything yourself even though the task feels impossible given your grief',score:0,feedbackText:'Writing entirely yourself is meaningful but struggling alone when AI can help is not more respectful to the person you are mourning. It is just harder on you.'},
  {text:'Share your memories and feelings with AI and ask it to help structure and phrase them — then make every word your own through editing',score:100,feedbackText:'Correct! AI assistance with emotional writing is a legitimate use. You provide the meaning; AI helps find the words. The eulogy is still entirely yours.'},
  {text:'Avoid AI completely for personal writing since it cannot understand human grief',score:-100,feedbackText:'AI does not grieve, but it can help translate your grief into language. The emotional authenticity comes from you — AI is a writing aid, not a ghostwriter of your feelings.'}
]},
{cat:'ai-everyday',d:2,s:'Your household uses multiple AI assistants from different companies. You notice they give different answers to the same factual question.',t:'Disagreement between AI assistants on factual questions signals that at least one is wrong. Primary source verification, not AI consensus, resolves factual disputes.',options:[
  {text:'Trust the AI brand you find most reliable since company reputation correlates with accuracy',score:0,feedbackText:'Brand reputation does not guarantee accuracy on any specific question. Even reliable AI systems have domains where their training data was limited or wrong.'},
  {text:'Treat disagreement as a flag that verification is needed and check a primary source such as an official website, encyclopedia, or subject expert',score:100,feedbackText:'Excellent! Disagreement between AI systems is a reliable signal that the question is beyond the confidence threshold of one or both. Primary source verification is always the answer.'},
  {text:'Ask a third AI system to settle the disagreement',score:-100,feedbackText:'A third AI opinion adds weight to one side but does not add evidence. If two AI systems disagree, the resolution comes from primary sources, not additional AI opinions.'}
]},
{cat:'ai-everyday',d:1,s:'You want to use AI to help sort through thousands of old family photos by identifying people and dates.',t:'AI photo organization tools can dramatically reduce the manual work of sorting large archives, but may misidentify people especially in older or lower-quality images.',options:[
  {text:'Trust AI identifications completely and delete images AI marks as duplicates',score:-100,feedbackText:'Deleting photos based on AI identification without review is irreversible and risky. AI misidentification in older images is common and photo loss in family archives is not recoverable.'},
  {text:'Use AI to create an initial organizational structure and groupings, then personally review AI identifications before applying any permanent labels or deletions',score:100,feedbackText:'Correct! AI as first-pass organizer dramatically reduces your workload while human review catches misidentifications before they are locked in. This is the right collaboration model.'},
  {text:'Organize the archive manually to ensure accuracy since family photos are irreplaceable',score:0,feedbackText:'Manual accuracy is valid but the scale of thousands of photos makes manual-only organization extremely time-consuming. AI plus review achieves both accuracy and feasibility.'}
]},
{cat:'ai-everyday',d:3,s:'You realize you have been using AI assistance so frequently for daily tasks that you have trouble completing some activities independently when AI is unavailable.',t:'AI dependency on cognitive tasks that used to be within your independent capacity is worth noticing and addressing through deliberate non-AI practice.',options:[
  {text:'Continue using AI since the efficiency gains outweigh any concern about dependency',score:0,feedbackText:'The trade-off may be reasonable for some tasks but not for capabilities you want to retain. The question is which skills matter to you independently and which you are comfortable outsourcing.'},
  {text:'Identify which capabilities matter to retain, practice those independently at regular intervals, and continue using AI for tasks where the dependency is not a concern',score:100,feedbackText:'Excellent! Selective dependency management is the right frame. Not all AI dependency is problematic — the key is conscious choice about which capacities you preserve and which you delegate.'},
  {text:'Stop using AI entirely since dependency means you have given up your autonomy',score:-100,feedbackText:'Eliminating all AI use to avoid dependency is disproportionate. Strategic use with deliberate independent practice for priority skills is a more nuanced and sustainable approach.'}
]},
{cat:'ai-everyday',d:2,s:'You want to use AI to help you understand a complex legal document you received. You are not a lawyer.',t:'AI can help non-lawyers understand legal language but cannot provide legal advice. Understanding a document is different from knowing how to respond to it.',options:[
  {text:'Have AI explain the document and act on its interpretation without consulting a lawyer',score:-100,feedbackText:'AI legal explanation is useful for comprehension but is not legal advice. Acting on AI interpretation of a document with legal consequences without professional review creates real risk.'},
  {text:'Use AI to identify and explain confusing clauses in plain language, then consult a lawyer for interpretation of any clause that requires action or response',score:100,feedbackText:'Correct! AI-assisted comprehension plus professional advice on consequential clauses is the right approach. AI makes the lawyer consultation more productive by clarifying what to ask.'},
  {text:'Ignore the document since legal language is too complex for non-lawyers to navigate even with AI help',score:0,feedbackText:'Ignoring legal documents is rarely safe. AI-assisted comprehension followed by professional advice is far better than avoidance.'}
]},
{cat:'ai-everyday',d:1,s:'You want to use AI to generate gift ideas for your partner based on their interests. The suggestions seem generic.',t:'AI gift suggestions improve dramatically with specific context. Vague input produces generic output — the more specific your prompt, the more useful the suggestions.',options:[
  {text:'Accept the generic suggestions since AI gift ideas are better than nothing',score:0,feedbackText:'Generic suggestions are only marginally better than nothing when the gift is for someone close. Specific input dramatically improves output quality.'},
  {text:'Give AI specific information: three to five specific interests, a recent conversation topic, the occasion, the budget, and your partner\'s gift preference style',score:100,feedbackText:'Excellent! Specificity is the key to useful AI suggestions. Vague prompts produce generic results; specific context produces genuinely tailored ideas.'},
  {text:'Stop using AI for gifts since personal choices should be human decisions',score:-100,feedbackText:'AI is a brainstorming tool, not the gift-giver. Using it to surface ideas you then evaluate and select is a legitimate and efficient use of the technology.'}
]},
{cat:'ai-everyday',d:2,s:'You want to use an AI personal finance assistant to track your spending and identify where you overspend.',t:'AI spending analysis tools find patterns that manual review misses, but require honest data input and category boundaries you define yourself.',options:[
  {text:'Connect your bank account to the AI and trust all category assignments it makes automatically',score:0,feedbackText:'Automatic category assignments are often inaccurate for ambiguous transactions. Reviewing category rules before trusting the analysis prevents misleading conclusions.'},
  {text:'Connect the bank account, review and correct the initial category assignments, then use AI insights to identify your three highest discretionary spending categories',score:100,feedbackText:'Correct! Human-verified categories plus AI pattern analysis is the right approach. The insights are only as good as the categorization accuracy, which requires initial human review.'},
  {text:'Track spending manually since connecting bank accounts to AI tools creates security risk',score:-100,feedbackText:'Reputable personal finance apps have bank-grade security for account connections. Manual tracking is always an option but the security risk argument does not hold for established tools.'}
]},
{cat:'ai-everyday',d:1,s:'You asked AI to help you write a birthday message for a close friend. The message feels impressive but not like you.',t:'AI writing assistance should enhance your voice, not replace it. The closer the relationship, the more your personal voice matters in the message.',options:[
  {text:'Send the AI-generated message since it is better written than what you would produce',score:0,feedbackText:'"Better written" is not the right criterion for a close friendship message. Authentic and slightly rough beats polished and impersonal in personal relationships.'},
  {text:'Use the AI message as a structure reference, then rewrite it in your own words and add a specific memory or inside reference only you and your friend share',score:100,feedbackText:'Excellent! Personal specificity is what makes birthday messages meaningful. AI provides structure; you provide the relationship detail that makes it real.'},
  {text:'Skip AI and write the message yourself even if it feels inadequate',score:-100,feedbackText:'Avoiding AI for personal messages is not necessary — using it thoughtfully as a drafting aid while making the message your own is legitimate and produces better results than a blank-page struggle.'}
]},
{cat:'ai-everyday',d:2,s:'Your commute takes 45 minutes each way. You want to use AI tools to make that time more productive.',t:'Commute time is valuable for learning, thinking, and planning but requires audio-first tools since visual interaction while traveling is unsafe or impractical.',options:[
  {text:'Respond to emails and messages using AI text assistance on your phone during the commute',score:-100,feedbackText:'Phone screen use during most commute types is either unsafe (driving) or socially awkward (crowded transit). Audio-first tools are more practical and usable without divided attention.'},
  {text:'Use AI-powered podcast summaries, audio briefings, or voice-driven note-taking to learn and capture ideas during the commute',score:100,feedbackText:'Correct! Audio-first AI tools fit commute constraints. Voice-driven tools let you capture ideas without looking at a screen, which is both safer and more sustainable as a daily habit.'},
  {text:'Use commute time for rest and keep AI productivity tools for the office',score:0,feedbackText:'Rest during commutes is valuable and appropriate. But if productivity is your goal, audio tools offer a low-intrusion way to add learning time without sacrificing recovery.'}
]},

// ===== ai-finance (20) =====
{cat:'ai-finance',d:1,s:'Your small business accountant wants to use AI to automatically categorize bank transactions. Some transactions are ambiguous.',t:'AI transaction categorization needs a defined rule-set and human review for ambiguous items to keep books accurate.',options:[
  {text:'Let AI auto-categorize all transactions and reconcile at year end',score:-100,feedbackText:'Year-end reconciliation of twelve months of miscategorized transactions is far more expensive than monthly review. Ambiguous transactions compound quickly.'},
  {text:'Configure AI to auto-categorize high-confidence transactions and flag ambiguous ones for monthly human review',score:100,feedbackText:'Correct! Confidence-threshold routing is the right design. AI handles the obvious volume; humans handle the ambiguous items before errors accumulate.'},
  {text:'Hire a bookkeeper instead of using AI since financial records require human judgment',score:0,feedbackText:'AI and bookkeepers can work together — AI handles high-volume routine categorization while bookkeepers handle complex items. The combination reduces cost without sacrificing accuracy.'}
]},
{cat:'ai-finance',d:2,s:'An AI investment tool claims it can predict which stocks will outperform the market next quarter with 80% accuracy.',t:'No AI investment tool has demonstrated sustained above-market prediction accuracy — such claims require extraordinary scrutiny before acting on them.',options:[
  {text:'Invest a portion of your portfolio based on the AI recommendations since 80% accuracy is impressive',score:-100,feedbackText:'Unverified 80% accuracy claims are a major red flag in financial services. Even if true historically, past model performance notoriously overstates future accuracy.'},
  {text:'Ask for the verified track record, independent audit results, and the methodology behind the claim before taking any investment action',score:100,feedbackText:'Excellent! Verified track record by an independent auditor is the only credible evidence for a prediction accuracy claim. Marketing numbers without audit are worthless.'},
  {text:'Invest a very small amount to test the AI\'s performance before committing more',score:0,feedbackText:'Small-scale testing is more prudent than full commitment but one quarter of results is statistically insufficient to validate an 80% accuracy claim. Ask for the historical record first.'}
]},
{cat:'ai-finance',d:1,s:'You want to use AI to create a personal budget based on your income and spending goals.',t:'AI budgeting tools are most useful when they work from actual transaction history rather than idealized income and expense estimates.',options:[
  {text:'Enter your approximate income and estimated expenses for AI to build a budget',score:0,feedbackText:'Estimated inputs produce aspirational budgets that rarely reflect real spending patterns. Actual transaction data reveals the real baseline AI needs to work with.'},
  {text:'Upload three months of real bank and credit card transactions for AI to analyze actual spending patterns, then set goals from the real baseline',score:100,feedbackText:'Correct! Actual data reveals the gap between assumed and real spending. AI budget recommendations built from real data are far more actionable than those built on estimates.'},
  {text:'Skip AI budgeting since managing money requires human discipline AI cannot provide',score:-100,feedbackText:'Discipline matters but clarity matters first. AI analysis of real spending reveals where discipline should be applied — without that data, effort goes to the wrong places.'}
]},
{cat:'ai-finance',d:2,s:'Your company CFO is excited about using AI to automate financial forecasting. The finance team worries about accountability for AI-generated forecasts.',t:'AI-generated forecasts require human review and sign-off because the forecaster, not the AI, remains accountable to stakeholders for the numbers.',options:[
  {text:'Let AI generate and publish forecasts directly to reduce the bottleneck of manual review',score:-100,feedbackText:'Removing human sign-off eliminates accountability. When AI forecasts are wrong — and they will be occasionally — someone must be responsible for the error and the response.'},
  {text:'Use AI to generate draft forecasts, require senior finance team member review and explicit sign-off before any forecast is published or acted on',score:100,feedbackText:'Excellent! AI acceleration plus human accountability is the right governance model for financial forecasts. The sign-off process maintains clear responsibility without slowing the benefit.'},
  {text:'Continue with manual forecasting since financial projections are too important for AI',score:0,feedbackText:'Manual forecasting at scale is slower and more error-prone than AI-assisted models with human review. The combination outperforms either alone for accuracy and speed.'}
]},
{cat:'ai-finance',d:3,s:'An AI model flags several of your company\'s routine financial transactions as potentially fraudulent. You believe the flags are false positives.',t:'AI fraud flags deserve investigation rather than either immediate acceptance or automatic dismissal — both errors carry significant cost.',options:[
  {text:'Override all AI flags immediately since your knowledge of the business means the transactions are legitimate',score:-100,feedbackText:'Automatic override eliminates the benefit of the AI layer. Even likely false positives deserve a fast documented investigation rather than blanket dismissal.'},
  {text:'Investigate each flagged transaction using the audit trail, document your findings, and resolve each flag with evidence rather than assumption',score:100,feedbackText:'Correct! Documented investigation of each flag — even when you expect to exonerate them — creates an audit trail that protects both you and the company if questions arise later.'},
  {text:'Escalate all flags to your compliance team since fraud flags require specialist review',score:0,feedbackText:'Escalating everything is conservative but creates unnecessary compliance team burden. A preliminary review by the transaction owner eliminates obvious false positives before escalation.'}
]},
{cat:'ai-finance',d:1,s:'You want AI to help you compare home mortgage options from three different lenders.',t:'AI mortgage comparison tools can calculate effective costs across multiple loan structures but the underlying assumptions must match your actual situation.',options:[
  {text:'Let AI compare the interest rates since that is the most important factor',score:0,feedbackText:'Interest rate alone is an incomplete comparison. APR, points, origination fees, and term length combine to determine the true cost of each loan.'},
  {text:'Give AI all loan parameters including APR, points, fees, and term length, then ask for total cost comparison at several different time horizons',score:100,feedbackText:'Excellent! Total cost comparison at multiple time horizons (5, 10, 20 years) reveals which loan wins under your specific expected ownership duration.'},
  {text:'Trust your bank\'s recommendation since they have access to your full financial profile',score:-100,feedbackText:'Your bank\'s recommendation reflects their products, not all available options. Independent AI comparison across multiple lenders gives you the market view your bank cannot.'}
]},
{cat:'ai-finance',d:2,s:'A fintech company wants to use AI to make loan approval decisions for small business applicants.',t:'AI loan decisions require explainability requirements — applicants are legally entitled to know why credit was denied in many jurisdictions.',options:[
  {text:'Deploy an AI model optimized purely for default prediction without worrying about explainability',score:-100,feedbackText:'Black-box loan decisions violate adverse action notice requirements in most jurisdictions. Regulatory compliance requires the ability to explain why any specific application was declined.'},
  {text:'Use an explainable AI model that generates specific denial reasons, build a human review process for borderline cases, and audit approval rates by demographic quarterly',score:100,feedbackText:'Correct! Explainability plus human review plus demographic auditing covers the three layers of responsible automated lending: transparency, oversight, and non-discrimination monitoring.'},
  {text:'Use AI only to pre-screen applications and have humans make all final decisions',score:0,feedbackText:'Full human final decisions preserve accountability but slow processing significantly. Explainable AI with human review of borderline cases is more scalable without sacrificing fairness.'}
]},
{cat:'ai-finance',d:1,s:'Your accounting software added an AI feature that suggests journal entries. You notice some suggestions seem incorrect.',t:'AI journal entry suggestions need review by qualified accountants since accounting errors compound into downstream reporting errors.',options:[
  {text:'Trust AI journal entry suggestions since the software provider is reputable',score:-100,feedbackText:'Reputable software providers still ship AI suggestions that do not account for your specific accounting policies. Every suggestion needs qualified review before posting.'},
  {text:'Review each AI-suggested journal entry against the source transaction and your chart of accounts before posting',score:100,feedbackText:'Correct! Source-to-suggestion verification is the minimum review standard. AI accelerates entry preparation but qualified review remains the accountant\'s non-delegable responsibility.'},
  {text:'Have a junior staff member approve all AI suggestions to save senior accountant time',score:0,feedbackText:'Junior reviewers may lack the judgment to catch policy-specific errors. Material journal entries need qualified review that matches the complexity of what is being posted.'}
]},
{cat:'ai-finance',d:2,s:'Your investment portfolio AI rebalanced your holdings automatically during a market volatility event in a way you did not intend.',t:'Automated investment tools must have clearly defined trigger rules and notification requirements so you know when and why rebalancing occurs.',options:[
  {text:'Accept the rebalance since the AI optimized based on its market model',score:0,feedbackText:'Accepting unrequested rebalancing without understanding the trigger teaches the AI that autonomous action outside your parameters is acceptable. Review the rules first.'},
  {text:'Review the trigger rule that caused the rebalance, adjust parameters to match your actual risk tolerance, and set up notifications for any future automated trades',score:100,feedbackText:'Excellent! Post-event audit plus parameter correction plus notification setup prevents future surprises. Automated investment tools must align with your actual risk preferences, not the default settings.'},
  {text:'Disable automated rebalancing entirely since it acted without your permission',score:-100,feedbackText:'Full disablement is one option but you lose the efficiency of automated rebalancing in normal conditions. Adjusting parameters is more proportionate than eliminating the feature.'}
]},
{cat:'ai-finance',d:3,s:'Your bank\'s AI fraud detection blocked a legitimate large international wire transfer and froze your account temporarily.',t:'AI fraud systems sometimes produce false positives on unusual-but-legitimate transactions. Documented escalation paths that work quickly are a measure of system quality.',options:[
  {text:'Accept the block as a reasonable safety measure and wait for the bank\'s process to resolve it',score:0,feedbackText:'Accepting the delay is reasonable if the timeline is acceptable. But knowing the escalation path and using it for business-critical transactions reduces wait time significantly.'},
  {text:'Contact the bank immediately using the fraud dispute channel, provide transaction documentation, and ask specifically for human review of the AI decision',score:100,feedbackText:'Correct! Documented escalation with evidence and an explicit request for human review is the fastest path through AI fraud false positives. The process exists for exactly this reason.'},
  {text:'Complain publicly about the bank\'s AI system since social media pressure resolves blocks faster',score:-100,feedbackText:'Public pressure may eventually work but creates an adversarial relationship with your bank. The documented internal escalation path resolves legitimate blocks more reliably.'}
]},
{cat:'ai-finance',d:1,s:'You want to use AI to analyze your company\'s three-year revenue trend and identify which products are underperforming.',t:'AI trend analysis can identify patterns across large datasets that manual Excel analysis typically misses, but the data quality it operates on determines the quality of its insights.',options:[
  {text:'Feed raw sales data to AI and act on whatever patterns it identifies',score:0,feedbackText:'Raw data may contain errors, category inconsistencies, and outliers that skew AI analysis. Data quality review before analysis prevents conclusions built on dirty inputs.'},
  {text:'Clean and validate the sales data first, then run AI analysis for trend identification, and cross-check flagged underperformers against qualitative factors like seasonal patterns and pricing changes',score:100,feedbackText:'Excellent! Clean data in, reliable insights out. Cross-checking AI pattern findings against qualitative knowledge prevents AI from misattributing normal seasonal patterns as underperformance.'},
  {text:'Use AI analysis results directly in your board presentation without additional validation',score:-100,feedbackText:'AI analysis findings presented to the board without validation create executive credibility risk. One obvious AI error in a board presentation erodes confidence in the entire analysis.'}
]},
{cat:'ai-finance',d:2,s:'A startup wants to use AI to generate financial models for investor due diligence. The founders have no finance background.',t:'AI-generated financial models need financial expert review before being shared with investors — errors in models are heavily scrutinized during due diligence.',options:[
  {text:'Use AI to generate the full financial model and share it with investors directly since AI is thorough',score:-100,feedbackText:'Investor due diligence will expose any errors in your financial model. AI-generated models without expert review frequently contain structural errors that professional investors identify immediately.'},
  {text:'Use AI to draft the model structure and populate initial assumptions, then have a finance professional review assumptions for realism and validate the model logic before investor sharing',score:100,feedbackText:'Correct! AI handles the model structure efficiently; expert review validates the assumptions that investors will interrogate. This combination is both efficient and credible.'},
  {text:'Hire a full financial modeling firm instead of using AI since investors expect professional-quality models',score:0,feedbackText:'Professional quality is achievable with AI plus expert review at a fraction of the cost of a full firm engagement. The combination produces investor-ready quality without the full firm price.'}
]},
{cat:'ai-finance',d:1,s:'Your company uses AI to generate monthly management reports. The CEO noticed a number that looked wrong and asked you to explain it.',t:'Being able to explain every number in an AI-generated report is a prerequisite for using AI in executive reporting.',options:[
  {text:'Tell the CEO the number comes from the AI and suggest asking the software vendor to explain it',score:-100,feedbackText:'Deferring to the vendor for explanation tells the CEO you do not understand your own reports. If you cannot explain the number, you should not have presented it.'},
  {text:'Trace the number back to its source data and calculation methodology in the AI system, then explain it in business terms to the CEO',score:100,feedbackText:'Excellent! Report ownership means being able to explain every number regardless of how it was generated. AI reports require this traceability before they go to executive audiences.'},
  {text:'Apologize for the error and regenerate the report',score:0,feedbackText:'Regenerating without understanding why the number looked wrong does not verify the new output is correct. Explanation and verification must precede any correction.'}
]},
{cat:'ai-finance',d:3,s:'Your AI trading algorithm performed exceptionally during the past bull market. You want to allocate more capital to it for the next year.',t:'Strategy performance in a single market regime does not validate performance across market conditions. Backtesting against diverse historical scenarios is required.',options:[
  {text:'Increase allocation since performance in the most recent period is the strongest signal of current strategy fitness',score:-100,feedbackText:'Recent bull market performance biases strategy assessment. Strategies that outperform in rising markets frequently underperform sharply when conditions change.'},
  {text:'Backtest the strategy across multiple market regimes including downturns before increasing allocation, and set a maximum drawdown limit before any rebalancing is triggered',score:100,feedbackText:'Correct! Multi-regime backtesting reveals where the strategy breaks. Drawdown limits ensure automated systems do not compound losses beyond your risk tolerance in adversarial conditions.'},
  {text:'Accept recent performance as validation but set a 6-month review to reassess',score:0,feedbackText:'A 6-month review is better than nothing but in a changing market, six months may be too late to reduce allocation before significant drawdown. Stress-test before scaling.'}
]},
{cat:'ai-finance',d:2,s:'A nonprofit organization wants to use AI to identify major donor prospects from its database of 50,000 contacts.',t:'AI donor prospect identification is most accurate when trained on your organization\'s own giving history rather than generic wealth screening models.',options:[
  {text:'Use a generic AI wealth screening service to identify the top 500 prospects from the contact list',score:0,feedbackText:'Generic wealth screening identifies who has money but not who cares about your cause. Organization-specific giving pattern analysis produces higher-quality prospect identification.'},
  {text:'Train AI on your own historic donor data to identify patterns in who gave, when they increased giving, and what engagement preceded major gifts, then score the prospect database',score:100,feedbackText:'Excellent! Organization-specific training produces prospect scores based on what actually drives giving to your cause. Generic wealth scores alone are a poor predictor of philanthropic engagement.'},
  {text:'Have development staff manually review all 50,000 contacts since major donor relationships require human judgment',score:-100,feedbackText:'Manual review of 50,000 contacts is not feasible at any reasonable staffing level. AI narrows the field to a manageable list that development staff can then engage personally.'}
]},
{cat:'ai-finance',d:1,s:'You want to use AI to automate invoice processing for your business. You currently process 200 invoices per month manually.',t:'AI invoice processing automation delivers ROI fastest when it focuses on high-volume, standardized vendor invoices first before tackling complex or variable ones.',options:[
  {text:'Automate all 200 invoices simultaneously from day one to maximize efficiency gains',score:0,feedbackText:'All-at-once automation without understanding which invoices are complex creates hidden error rates. Segmenting by complexity lets you validate AI accuracy before full deployment.'},
  {text:'Categorize invoices by standardization level, automate the highest-volume standard invoices first, validate accuracy over 60 days, then expand to more complex invoices',score:100,feedbackText:'Correct! Staged deployment by complexity lets you build confidence incrementally. Error detection in standard invoices prevents those errors from scaling to your entire volume.'},
  {text:'Keep processing invoices manually since financial documents require human verification',score:-100,feedbackText:'Manual processing at 200 invoices per month is a significant time cost. AI automation with staged deployment and human verification for exceptions delivers efficiency without accuracy sacrifice.'}
]},
{cat:'ai-finance',d:2,s:'A private equity firm wants to use AI to screen acquisition targets faster. They currently review 500 companies per year manually.',t:'AI deal screening accelerates review by filtering on financial thresholds and strategic criteria, allowing human attention to focus on genuinely promising targets.',options:[
  {text:'Use AI to automatically identify the top 20 acquisition targets and focus all due diligence there',score:0,feedbackText:'AI-only narrowing to 20 targets risks systematic exclusion of targets that fit your criteria but do not match the AI\'s learned patterns. Human review of AI-flagged candidates is still needed.'},
  {text:'Use AI to screen all 500 for defined financial and strategic criteria, produce a ranked shortlist of 50, then have investment professionals conduct qualitative assessment on the shortlist',score:100,feedbackText:'Excellent! AI handles the quantitative filter at volume; humans apply the qualitative judgment that pattern-matching alone misses. The shortlist size balances efficiency with coverage.'},
  {text:'Hire more analysts to review all 500 targets manually since PE decisions require deep human judgment',score:-100,feedbackText:'Adding analysts to review volume that AI can screen is an inefficient use of human capital. The analysts\' irreplaceable judgment belongs on the shortlist, not the full 500.'}
]},
{cat:'ai-finance',d:1,s:'Your finance team is considering using an AI tool that promises to reduce month-end close from five days to two days.',t:'Close acceleration claims need specific workflow analysis to identify which of the five days AI actually eliminates versus which require human judgment that stays.',options:[
  {text:'Purchase the tool based on the three-day reduction claim since close efficiency is a clear finance priority',score:0,feedbackText:'The claim may be achievable but requires verification against your specific close workflow. Generic benchmarks may not account for your complexity or existing automation.'},
  {text:'Map your current close workflow by day to identify which activities are candidates for AI acceleration, then evaluate whether the tool addresses those specific activities',score:100,feedbackText:'Correct! Workflow mapping before purchase reveals whether the tool solves your actual bottlenecks or accelerates steps that are not your constraint. This prevents buying the wrong solution.'},
  {text:'Trial the tool for one month-end cycle before deciding on purchase',score:-100,feedbackText:'A one-cycle trial is better than no trial but one month-end is insufficient to validate the three-day improvement claim against your full workflow. The workflow analysis should precede the trial.'}
]},
{cat:'ai-finance',d:3,s:'AI regulatory compliance monitoring tools can now scan all your company\'s financial communications for compliance violations before they become problems.',t:'AI compliance monitoring is a powerful tool for risk reduction but requires clear policies on what constitutes a violation and defined escalation paths for flagged content.',options:[
  {text:'Deploy AI compliance monitoring with full access to all financial communications immediately',score:0,feedbackText:'Immediate deployment without policy definition creates ambiguity about what constitutes a violation and what happens to false positives. Policy first, technology second.'},
  {text:'Define violation categories and escalation procedures first, then deploy AI monitoring on a representative sample to validate accuracy before full deployment',score:100,feedbackText:'Excellent! Policy-before-technology is the right sequence for compliance tools. Sample validation before full deployment catches classification errors before they trigger false escalations at scale.'},
  {text:'Avoid AI compliance monitoring since employees have a right to privacy in their communications',score:-100,feedbackText:'Business communications in regulated industries have defined compliance monitoring obligations. AI monitoring that complies with disclosure requirements is both legal and increasingly expected.'}
]},

// ===== ai-health (20) =====
{cat:'ai-health',d:1,s:'You have a skin rash that appeared three days ago. An AI symptom checker suggests it might be several different conditions including one serious one.',t:'AI symptom checkers are useful for general orientation but cannot replace clinical diagnosis. Concerning symptoms need professional evaluation.',options:[
  {text:'Treat the most serious condition the AI listed since it is better to be safe',score:-100,feedbackText:'Self-treating for the most serious possible diagnosis based on an AI list leads to unnecessary treatment for conditions you likely do not have. Clinical evaluation determines what is actually happening.'},
  {text:'Use the AI suggestions to understand what questions to ask, then see a doctor or dermatologist for actual diagnosis',score:100,feedbackText:'Correct! AI orientation for symptom understanding is legitimate. It helps you ask better questions in clinical consultation rather than replacing that consultation.'},
  {text:'Monitor the rash for two more weeks before deciding if it warrants medical attention',score:0,feedbackText:'Waiting two more weeks on a rash that has been present for three days and includes a serious condition flag is not the right response. A clinical evaluation now is more appropriate.'}
]},
{cat:'ai-health',d:2,s:'A hospital wants to use AI to help radiologists detect lung cancer earlier in CT scans. The AI has a 94% sensitivity rate.',t:'AI medical imaging tools that assist radiologists must be validated on the specific patient population and equipment the hospital uses, not just the training dataset.',options:[
  {text:'Deploy the AI for all CT scan review immediately since 94% sensitivity improves on radiologist-only detection',score:0,feedbackText:'Validation on the training dataset does not guarantee the same performance on your patient population and equipment. Performance validation on your specific context is required before deployment.'},
  {text:'Validate the AI\'s sensitivity and specificity on a representative sample of your hospital\'s actual CT scans before deployment, then use it as a second reader alongside radiologists',score:100,feedbackText:'Excellent! Local validation plus second-reader workflow is the responsible deployment model. AI-assisted reading improves detection without replacing the radiologist\'s clinical judgment.'},
  {text:'Reject the AI tool since medical diagnosis must remain entirely with radiologists',score:-100,feedbackText:'AI assistance with a defined radiologist-in-the-loop workflow improves outcomes in proven clinical use. Categorical rejection of validated AI assistance foregoes real patient benefit.'}
]},
{cat:'ai-health',d:1,s:'Your company wants to use wearable health device data collected from employee wellness programs to improve workplace health policies.',t:'Employee health data is highly sensitive and its use for policy decisions requires explicit consent frameworks and strict anonymization before analysis.',options:[
  {text:'Analyze employee health data to identify wellness trends and implement company policies based on findings',score:-100,feedbackText:'Using identifiable employee health data for management decisions is likely illegal under HIPAA and similar frameworks, and breaches the trust employees placed in the wellness program.'},
  {text:'Aggregate and anonymize the data before analysis, obtain legal review for the use case, and be transparent with employees about how aggregate data informs policy',score:100,feedbackText:'Correct! Anonymization, legal review, and transparency are the three prerequisites for ethical use of employee wellness data in policy decisions.'},
  {text:'Use only voluntarily submitted wellness survey data rather than wearable device data',score:0,feedbackText:'Survey-only data avoids the wearable consent issue but the core principle remains the same: transparent use with proper anonymization applies to any employee health data.'}
]},
{cat:'ai-health',d:2,s:'An AI mental health chatbot claims it can provide therapy-level support for depression and anxiety. You are considering recommending it to your employees.',t:'AI mental health tools can provide supplementary support and psychoeducation but are not substitutes for clinical therapy for moderate to severe conditions.',options:[
  {text:'Recommend the AI chatbot as a cost-effective replacement for the employee assistance program',score:-100,feedbackText:'AI chatbots are not equivalent to licensed clinical therapy. For moderate to severe depression and anxiety, AI-only support may delay proper treatment with serious consequences.'},
  {text:'Offer the AI tool as a supplementary resource alongside the EAP, positioning it for mild stress and self-help while making clinical referrals easy for more serious presentations',score:100,feedbackText:'Excellent! Supplementary positioning with clear clinical pathways is responsible deployment. AI mental health tools add value in the mild and subclinical range where clinical resources are scarce.'},
  {text:'Reject the AI tool since mental health support must always involve licensed professionals',score:0,feedbackText:'AI tools for self-help, stress management, and psychoeducation have evidence-based value in the mild range. Categorical rejection ignores legitimate supplementary applications.'}
]},
{cat:'ai-health',d:1,s:'You want to use an AI nutrition app to optimize your diet for athletic performance. The app suggests eliminating several food groups.',t:'Extreme elimination diets recommended by AI apps without individual clinical assessment can create nutrient deficiencies in athletes.',options:[
  {text:'Follow the AI\'s food group elimination plan exactly since it is designed for athletic optimization',score:-100,feedbackText:'AI nutrition apps optimize for general patterns, not your individual biochemistry. Eliminating food groups without clinical assessment creates real deficiency risk, especially for athletes.'},
  {text:'Use the AI suggestions as a starting point and consult a sports dietitian before making significant dietary changes',score:100,feedbackText:'Correct! AI nutrition apps provide useful general guidance. A sports dietitian validates recommendations against your specific needs, training load, and any individual metabolic factors.'},
  {text:'Ignore the AI nutrition app since athlete nutrition requires professional guidance exclusively',score:0,feedbackText:'AI nutrition tools offer legitimate educational value and general guidance. Using them alongside professional consultation is more useful than dismissing them entirely.'}
]},
{cat:'ai-health',d:2,s:'A healthcare provider wants to use AI to predict patient no-shows and automatically overbook appointments to fill the gaps.',t:'AI overbooking models must account for the impact on patients who do show up on time and balance efficiency gains against patient experience costs.',options:[
  {text:'Implement AI overbooking aggressively to maximize appointment slot utilization',score:-100,feedbackText:'Aggressive overbooking that regularly produces patient waiting harms patient experience and can create access issues for the patients who did keep their appointments.'},
  {text:'Use AI predictions to implement conservative overbooking at rates that reduce empty slots without creating systematic patient waiting, and monitor patient experience scores',score:100,feedbackText:'Excellent! Conservative overbooking calibrated to prediction accuracy and monitored against patient experience metrics captures efficiency while protecting the patient relationship.'},
  {text:'Stick with current scheduling since overbooking creates ethical issues regardless of AI prediction quality',score:0,feedbackText:'Many providers use overbooking as standard practice because no-shows are a real operational problem. AI-informed conservative overbooking can be ethical if calibrated carefully.'}
]},
{cat:'ai-health',d:3,s:'An AI model identifies that patients of a specific demographic group are being under-prescribed pain medication compared to clinical guidelines.',t:'AI health equity audits that surface systematic disparities must be followed by root cause investigation and clinical practice change, not just awareness.',options:[
  {text:'Note the finding for further study and continue current prescribing practices pending a full research project',score:0,feedbackText:'"Further study" without immediate action on a documented disparity in pain treatment allows ongoing patient harm. Research does not need to precede operational response.'},
  {text:'Investigate the root causes with the clinical team, implement immediate prescribing guidance, and set a review timeline to measure whether the disparity decreases',score:100,feedbackText:'Correct! AI equity audits create an obligation to act. Root cause investigation plus immediate guidance plus outcome measurement is the complete responsible response.'},
  {text:'Ignore the finding since AI analysis of clinical decisions may reflect clinically legitimate factors',score:-100,feedbackText:'Dismissing equity audit findings without investigation perpetuates harm. Even if some of the disparity reflects legitimate clinical factors, the assumption should not be that all of it does.'}
]},
{cat:'ai-health',d:1,s:'You want to use AI to create a sleep improvement plan based on your smartwatch sleep tracking data.',t:'AI sleep analysis tools identify patterns in your data but sleep intervention recommendations that involve significant schedule changes should be validated against your lifestyle.',options:[
  {text:'Follow the AI sleep plan recommendations exactly and change your entire schedule to match',score:0,feedbackText:'Sleep timing recommendations must fit your actual life constraints. An AI plan built from data alone without lifestyle context will produce conflicting guidance you cannot realistically follow.'},
  {text:'Use AI to identify the two to three biggest sleep disruption patterns in your data, then make targeted changes to those specific factors',score:100,feedbackText:'Excellent! Targeted changes based on identified patterns are more actionable than comprehensive schedule overhauls. AI analysis of your own data is a legitimate starting point for sleep improvement.'},
  {text:'Ignore AI sleep analysis since sleep is complex and individual variation makes general AI recommendations unreliable',score:-100,feedbackText:'Your own sleep data analyzed by AI is not general AI advice — it is pattern detection in your specific data. That is a legitimate and valuable use of AI health tools.'}
]},
{cat:'ai-health',d:2,s:'A pharmaceutical company wants to use AI to accelerate drug discovery by predicting which molecular structures are likely to be effective.',t:'AI drug discovery acceleration requires that computational predictions are validated through conventional biological and clinical testing pipelines — it accelerates hypothesis generation, not the testing process.',options:[
  {text:'Use AI predictions to skip early-stage biological testing and go directly to clinical trials',score:-100,feedbackText:'Skipping biological testing based on AI predictions bypasses the safety and efficacy validation that clinical trial pipelines depend on. AI prediction quality does not substitute for experimental evidence.'},
  {text:'Use AI to generate a ranked shortlist of candidate molecules for experimental testing, then proceed through the standard validation pipeline for the top candidates',score:100,feedbackText:'Correct! AI narrows the search space dramatically; conventional testing validates what AI cannot. The combination accelerates discovery without circumventing necessary safety validation.'},
  {text:'Avoid AI in drug discovery since pharmaceutical decisions must be grounded in conventional experimental evidence',score:0,feedbackText:'AI-assisted hypothesis generation that is then validated through conventional testing is a powerful and legitimate use. Categorical rejection ignores significant acceleration potential.'}
]},
{cat:'ai-health',d:1,s:'An elderly patient wants to use an AI voice assistant to help manage their daily medications. Their family is concerned about errors.',t:'AI medication reminder systems must be tested against the patient\'s specific medication complexity and have clear escalation paths when reminders are missed.',options:[
  {text:'Set up any available AI reminder system since any reminder is better than none',score:0,feedbackText:'Any reminder is better than none but a system that fails silently when doses are missed does not prevent the medication error the family is concerned about.'},
  {text:'Configure the reminder system with the specific medication schedule, test it for one week with family monitoring, set up missed-dose alerts to a family member, and confirm the patient can use the interface independently',score:100,feedbackText:'Excellent! Test period plus escalation alerts plus confirmed patient usability is the complete responsible setup. Each element addresses a specific failure mode in medication reminder technology.'},
  {text:'Hire a medication management service since AI reminder systems are not reliable enough for elderly patients on complex regimens',score:-100,feedbackText:'AI reminder systems have demonstrated real value in medication adherence. The concern about reliability is addressed through proper setup and monitoring, not categorical rejection.'}
]},
{cat:'ai-health',d:2,s:'Your hospital is considering using AI to triage emergency department patients and recommend initial treatment protocols.',t:'AI triage assistance in emergency settings requires a defined human override protocol and ongoing performance monitoring since errors have life-threatening consequences.',options:[
  {text:'Implement AI triage recommendations as default treatment protocols with physicians able to override if they choose',score:0,feedbackText:'Default-to-AI with optional override inverts the appropriate authority structure. In life-critical decisions, AI should inform physician judgment, not become the default protocol.'},
  {text:'Use AI as a second opinion tool that surfaces the recommended triage category for physician review, with mandatory human sign-off on all treatment protocol initiations',score:100,feedbackText:'Correct! Second-opinion positioning with mandatory human sign-off is the right framework for AI in life-critical clinical decisions. AI surfaces and structures; physicians decide and act.'},
  {text:'Avoid AI in emergency triage since the stakes are too high for algorithmic decision-making',score:-100,feedbackText:'AI as a decision support tool in emergency settings with physician oversight can improve triage accuracy. Categorical rejection based on stakes misses the benefit of AI-assisted decision support.'}
]},
{cat:'ai-health',d:1,s:'You want to use AI to analyze your genetic test results and understand your health risks.',t:'AI interpretation of genetic data requires expert context because genetic risk is probabilistic, not deterministic, and lifestyle factors often outweigh genetic predisposition.',options:[
  {text:'Use AI to interpret your genetic results and make major health decisions based on risk scores',score:-100,feedbackText:'Genetic risk scores are probabilities, not diagnoses. Major health decisions based on genetic data alone without clinical context regularly produce unnecessary anxiety and inappropriate action.'},
  {text:'Use AI for initial orientation on what the genetic markers mean, then consult a genetic counselor to understand risk in the context of your family history and lifestyle',score:100,feedbackText:'Excellent! AI for orientation plus genetic counselor for clinical context is the right combination. A counselor contextualizes risk in ways an AI tool cannot given your complete picture.'},
  {text:'Ignore genetic testing results since they are statistical and do not determine your health future',score:0,feedbackText:'Ignoring genetic risk information entirely wastes an opportunity for informed prevention. The goal is accurate interpretation of probabilistic risk, not action based on certainty.'}
]},
{cat:'ai-health',d:3,s:'AI analysis of your company\'s health insurance claims data could identify employees with chronic conditions and target them for wellness program enrollment.',t:'Using insurance claims data to target employees with conditions creates discrimination risk and can deter future claims out of fear of identification.',options:[
  {text:'Use the claims data to proactively enroll high-risk employees in wellness programs since earlier intervention improves outcomes',score:-100,feedbackText:'Targeting employees with conditions based on claims data creates legal discrimination exposure and destroys employee trust in the insurance program\'s confidentiality.'},
  {text:'Make wellness programs broadly available and market them to all employees equally without using claims data to identify or target specific individuals',score:100,feedbackText:'Correct! Universal availability protects employee privacy and avoids the discrimination risk of condition-targeted enrollment. High-risk employees who want support can self-select in.'},
  {text:'Aggregate claims data at the department level to target wellness programs without identifying individuals',score:0,feedbackText:'Department-level aggregation reduces individual identification risk but may still target small departments where individuals are identifiable. Legal review of this approach is needed before implementation.'}
]},
{cat:'ai-health',d:2,s:'A fitness AI coach has set your training plan at a level you find too intense, and you are experiencing joint pain.',t:'AI fitness programs optimize for performance metrics but cannot feel pain signals. Pain is clinical information that requires human judgment, not algorithmic adjustment.',options:[
  {text:'Push through the pain since the AI has calculated the optimal training load for your goals',score:-100,feedbackText:'AI training load optimization does not include pain signal feedback. Joint pain is a physiological warning that should not be overridden by algorithm output.'},
  {text:'Stop the painful activity, consult a physical therapist or sports medicine professional, and provide that clinical input before continuing or modifying the AI plan',score:100,feedbackText:'Correct! Pain is clinical information outside AI competence. Professional assessment before modifying or continuing the plan prevents injury that would set back training more than the pause.'},
  {text:'Reduce the AI-prescribed intensity by 20% and continue, assuming the pain is normal training soreness',score:0,feedbackText:'Self-adjusting without clinical assessment of joint pain is risky. The distinction between training soreness and injury pain requires professional judgment, not algorithm modification.'}
]},
{cat:'ai-health',d:1,s:'A public health agency wants to use AI to predict flu outbreak locations two weeks in advance based on social media and pharmacy data.',t:'AI public health prediction is most valuable when it triggers early resource staging and communication, not just adds to the information available without action.',options:[
  {text:'Use AI predictions to generate weekly reports for public health officials to read',score:0,feedbackText:'Predictions that produce reports without triggering action miss the intervention opportunity the advance notice creates. Prediction value comes from enabling earlier response.'},
  {text:'Connect AI predictions to pre-defined response protocols: early vaccine distribution, clinic staffing alerts, and public messaging triggers that activate automatically at defined thresholds',score:100,feedbackText:'Excellent! Prediction-to-action protocols capture the value of early warning. A two-week lead time is only useful if it triggers different action than a zero-lead-time response.'},
  {text:'Share predictions publicly so communities can self-protect since government response is too slow to capitalize on advance warning',score:-100,feedbackText:'Public prediction sharing without coordinated response creates anxiety without proportionate protection. Official response coordination is more effective than individual self-protection.'}
]},
{cat:'ai-health',d:2,s:'You want to use AI to monitor your own mental health over time by analyzing your writing and voice recordings.',t:'Personal AI mental health monitoring tools can surface useful patterns but require mental health professional context to interpret meaningfully.',options:[
  {text:'Use AI mental health monitoring as the primary tool for understanding your psychological wellbeing over time',score:0,feedbackText:'Self-monitoring as the primary tool misses the clinical context needed to interpret what patterns mean. AI-identified trends are useful as one input alongside professional assessment.'},
  {text:'Use AI monitoring to identify patterns and bring them to therapy sessions as data points for professional interpretation and clinical discussion',score:100,feedbackText:'Correct! Personal monitoring as data for professional interpretation is the optimal use. Your therapist gains longitudinal data; you gain structured insight to bring to sessions.'},
  {text:'Avoid personal AI mental health monitoring since analyzing your own mental state can increase anxiety',score:-100,feedbackText:'Some people do experience monitoring-related anxiety. But the monitoring itself is not the cause — appropriate use involves checking trends occasionally with professional support, not obsessive tracking.'}
]},
{cat:'ai-health',d:1,s:'An AI diagnostic tool correctly identified a condition in your patient but suggested a treatment protocol you know is outdated.',t:'AI clinical decision support tools may have training cutoffs that predate current clinical guidelines. Physicians must cross-check AI recommendations against current standards.',options:[
  {text:'Follow the AI treatment recommendation since the diagnostic identification was accurate',score:-100,feedbackText:'Diagnostic accuracy does not validate treatment recommendations. AI tools may have knowledge cutoffs that predate current guidelines, especially for rapidly evolving treatment areas.'},
  {text:'Use the correct diagnosis and cross-reference the treatment recommendation against current clinical guidelines before proceeding',score:100,feedbackText:'Excellent! AI diagnostic support plus current guideline verification is the right clinical workflow. Accurate diagnosis with outdated treatment is still harmful.'},
  {text:'Avoid AI diagnostic tools entirely since clinical decisions require the most current evidence',score:0,feedbackText:'AI diagnostic support with physician verification is a legitimate and valuable tool. The verification step ensures currency without discarding the diagnostic assistance.'}
]},
{cat:'ai-health',d:3,s:'An AI system analyzing hospital patient data identified a pattern suggesting a specific nursing team has higher patient complication rates than comparable teams.',t:'AI quality monitoring findings about clinical teams require structured investigation through proper clinical governance channels before any action is taken.',options:[
  {text:'Confront the nursing team with the AI finding and require immediate changes to their practices',score:-100,feedbackText:'Acting on AI data without investigation could target a team for confounders the AI cannot see: patient acuity mix, resource constraints, or data anomalies that explain the pattern.'},
  {text:'Initiate a structured quality review with clinical leadership, examine potential confounders like patient acuity and staffing levels, and involve the team in the investigation process',score:100,feedbackText:'Correct! Structured clinical governance review is the right channel for AI quality findings. Confounders must be investigated before any conclusion about team performance is drawn.'},
  {text:'Share the AI findings with hospital administration immediately to prompt action',score:0,feedbackText:'Administrative escalation before clinical investigation bypasses the clinical governance process and may result in disciplinary action for a statistical artifact rather than a real quality issue.'}
]},
{cat:'ai-health',d:2,s:'Your company offers an AI-powered health coaching chatbot as an employee benefit. A user shares they are having thoughts of self-harm.',t:'AI health tools must have defined crisis protocols that immediately connect users disclosing self-harm to crisis services, regardless of the tool\'s primary function.',options:[
  {text:'Configure the chatbot to respond with general wellness content and suggest the user speak with a professional when ready',score:-100,feedbackText:'General wellness content in response to a self-harm disclosure is an inadequate and potentially dangerous non-response. Crisis disclosure requires immediate crisis resource connection, not general wellness guidance.'},
  {text:'Program an immediate crisis protocol that recognizes self-harm disclosures, stops the normal chatbot flow, provides crisis line information, and notifies a clinical team if consent was given',score:100,feedbackText:'Excellent! Crisis protocol design for AI health tools is not optional. The protocol must recognize the disclosure, respond with crisis resources, and escalate according to pre-established clinical governance.'},
  {text:'Remove the AI health chatbot since mental health tools carry too much risk for employer deployment',score:0,feedbackText:'The risk is manageable with proper crisis protocol design. Removing the tool entirely denies benefit to the majority of users who engage safely. The answer is better protocol design, not removal.'}
]}

]

for(let i=0; i<ALL.length; i+=20) {
  const batch = ALL.slice(i, i+20)
  const cat = batch[0].cat
  process.stdout.write(`Inserting ${batch.length} ${cat} questions... `)
  const ok = await insert(batch)
  if(!ok) { console.error('FAILED at index', i); break }
}
console.log('DONE. Total:', ALL.length)
